        #region Conversion Methods

        /// <summary>
        ///     Convert to the unit representation <paramref name="unit" />.
        /// </summary>
        /// <returns>Value converted to the specified unit.</returns>
        public double As(NominalPowerUnit unit)
        {
            if (Unit == unit)
                return Value;

            return ToUnit(unit).Value;
        }

        /// <inheritdoc cref="IQuantity.As(UnitKey)"/>
        public double As(UnitKey unitKey)
        {
            return As(unitKey.ToUnit<NominalPowerUnit>());
        }

        /// <summary>
        ///     Converts this NominalPower to another NominalPower with the unit representation <paramref name="unit" />.
        /// </summary>
        /// <param name="unit">The unit to convert to.</param>
        /// <returns>A NominalPower with the specified unit.</returns>
        public NominalPower ToUnit(NominalPowerUnit unit)
        {
            return ToUnit(unit, DefaultConversionFunctions);
        }

        /// <summary>
        ///     Converts this <see cref="NominalPower"/> to another <see cref="NominalPower"/> using the given <paramref name="unitConverter"/> with the unit representation <paramref name="unit" />.
        /// </summary>
        /// <param name="unit">The unit to convert to.</param>
        /// <param name="unitConverter">The <see cref="UnitConverter"/> to use for the conversion.</param>
        /// <returns>A NominalPower with the specified unit.</returns>
        public NominalPower ToUnit(NominalPowerUnit unit, UnitConverter unitConverter)
        {
            if (TryToUnit(unit, out var converted))
            {
                // Try to convert using the auto-generated conversion methods.
                return converted!.Value;
            }
            else if (unitConverter.TryGetConversionFunction((typeof(NominalPower), Unit, typeof(NominalPower), unit), out var conversionFunction))
            {
                // See if the unit converter has an extensibility conversion registered.
                return (NominalPower)conversionFunction(this);
            }
            else if (Unit != BaseUnit)
            {
                // Conversion to requested unit NOT found. Try to convert to BaseUnit, and then from BaseUnit to requested unit.
                var inBaseUnits = ToUnit(BaseUnit);
                return inBaseUnits.ToUnit(unit);
            }
            else
            {
                // No possible conversion
                throw new UnitNotFoundException($"Can't convert {Unit} to {unit}.");
            }
        }

        /// <summary>
        ///     Attempts to convert this <see cref="NominalPower"/> to another <see cref="NominalPower"/> with the unit representation <paramref name="unit" />.
        /// </summary>
        /// <param name="unit">The unit to convert to.</param>
        /// <param name="converted">The converted <see cref="NominalPower"/> in <paramref name="unit"/>, if successful.</param>
        /// <returns>True if successful, otherwise false.</returns>
        private bool TryToUnit(NominalPowerUnit unit, [NotNullWhen(true)] out NominalPower? converted)
        {
            if (Unit == unit)
            {
                converted = this;
                return true;
            }

            NominalPower? convertedOrNull = (Unit, unit) switch
            {
                // NominalPowerUnit -> BaseUnit
                (NominalPowerUnit.DecawattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e1d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.DeciwattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e-1d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.FemtowattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e-15d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.GigawattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e9d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.KilowattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e3d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.MegawattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e6d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.MicrowattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e-6d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.MilliwattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e-3d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.NanowattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e-9d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.PetawattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e15d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.PicowattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e-12d, NominalPowerUnit.WattPeak),
                (NominalPowerUnit.TerawattPeak, NominalPowerUnit.WattPeak) => new NominalPower((_value) * 1e12d, NominalPowerUnit.WattPeak),

                // BaseUnit -> NominalPowerUnit
                (NominalPowerUnit.WattPeak, NominalPowerUnit.DecawattPeak) => new NominalPower((_value) / 1e1d, NominalPowerUnit.DecawattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.DeciwattPeak) => new NominalPower((_value) / 1e-1d, NominalPowerUnit.DeciwattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.FemtowattPeak) => new NominalPower((_value) / 1e-15d, NominalPowerUnit.FemtowattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.GigawattPeak) => new NominalPower((_value) / 1e9d, NominalPowerUnit.GigawattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.KilowattPeak) => new NominalPower((_value) / 1e3d, NominalPowerUnit.KilowattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.MegawattPeak) => new NominalPower((_value) / 1e6d, NominalPowerUnit.MegawattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.MicrowattPeak) => new NominalPower((_value) / 1e-6d, NominalPowerUnit.MicrowattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.MilliwattPeak) => new NominalPower((_value) / 1e-3d, NominalPowerUnit.MilliwattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.NanowattPeak) => new NominalPower((_value) / 1e-9d, NominalPowerUnit.NanowattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.PetawattPeak) => new NominalPower((_value) / 1e15d, NominalPowerUnit.PetawattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.PicowattPeak) => new NominalPower((_value) / 1e-12d, NominalPowerUnit.PicowattPeak),
                (NominalPowerUnit.WattPeak, NominalPowerUnit.TerawattPeak) => new NominalPower((_value) / 1e12d, NominalPowerUnit.TerawattPeak),

                _ => null
            };

            if (convertedOrNull is null)
            {
                converted = default;
                return false;
            }

            converted = convertedOrNull.Value;
            return true;
        }

