        double IQuantity.As(Enum unit)
        {
            if (unit is not NominalPowerUnit typedUnit)
                throw new ArgumentException($"The given unit is of type {unit.GetType()}. Only {typeof(NominalPowerUnit)} is supported.", nameof(unit));

            return As(typedUnit);
        }

        /// <inheritdoc />
        IQuantity IQuantity.ToUnit(Enum unit)
        {
            if (!(unit is NominalPowerUnit typedUnit))
                throw new ArgumentException($"The given unit is of type {unit.GetType()}. Only {typeof(NominalPowerUnit)} is supported.", nameof(unit));

            return ToUnit(typedUnit, DefaultConversionFunctions);
        }

        /// <inheritdoc />
        IQuantity<NominalPowerUnit> IQuantity<NominalPowerUnit>.ToUnit(NominalPowerUnit unit) => ToUnit(unit);

